1	import { Router } from "express";
2	import { posts, nextId } from "../db.js";
3	import { Post } from "../types.js";
4	
5	const router = Router();
6	
7	// GET /posts - list all posts
8	router.get("/", (req, res) => {
9	  res.json(posts);
10	});
11	
12	// GET /posts/:id - get a single post
13	router.get("/:id", (req, res) => {
14	  const id = parseInt(req.params.id, 10);
15	  const post = posts.find((p) => p.id === id);
16	  if (!post) {
17	    res.status(404).json({ error: "Post not found" });
18	    return;
19	  }
20	  res.json(post);
21	});
22	
23	// POST /posts - create a new post
24	router.post("/", (req, res) => {
25	  const { title, content, userId } = req.body;
26	  if (!title || !content) {
27	    res.status(400).json({ error: "title and content are required" });
28	    return;
29	  }
30	  const newPost: Post = {
31	    id: nextId(posts),
32	    title,
33	    content,
34	    userId: userId || 1,
35	    createdAt: new Date().toISOString(),
36	  };
37	  posts.push(newPost);
38	  res.status(201).json(newPost);
39	});
40	
41	// PUT /posts/:id - update a post
42	router.put("/:id", (req, res) => {
43	  const id = parseInt(req.params.id, 10);
44	  const index = posts.findIndex((p) => p.id === id);
45	  if (index === -1) {
46	    res.status(404).json({ error: "Post not found" });
47	    return;
48	  }
49	  const { title, content } = req.body;
50	  if (title) posts[index].title = title;
51	  if (content) posts[index].content = content;
52	  res.json(posts[index]);
53	});
54	
55	// DELETE /posts/:id - delete a post
56	router.delete("/:id", (req, res) => {
57	  const id = parseInt(req.params.id, 10);
58	  const index = posts.findIndex((p) => p.id === id);
59	  if (index === -1) {
60	    res.status(404).json({ error: "Post not found" });
61	    return;
62	  }
63	  const deleted = posts.splice(index, 1);
64	  res.json(deleted[0]);
65	});
66	
67	export { router as postsRouter };
