describe("Auth - Registration", () => {
  it("POST /auth/register should create a new user and return a token", async () => {
    const res = await request(app).post("/auth/register").send({
      username: "newuser",
      email: "newuser@example.com",
      password: "mypassword",
    });
    expect(res.status).toBe(201);
