      username: "alice_owner",
      email: "alice_owner@example.com",
      password: "alicepass",
    });
    aliceToken = aliceRes.body.token;

    const bobRes = await request(app).post("/auth/register").send({
      username: "bob_owner",
      email: "bob_owner@example.com",
      password: "bobpass",
