    const postRes = await request(app)
      .post("/posts")
      .set("Authorization", `Bearer ${aliceToken}`)
      .send({
        title: "Alice's Post",
        content: "Only Alice can modify this",
      });
    alicePostId = postRes.body.id;
  });

  it("owner can update their own post", async () => {
